// 新增候选选择器
const VIDEO_SELECTORS = [
  '.video-item',                     // 原选择器（向后兼容）
  '[data-testid="video-card"]',      // 测试 ID
  '.video-card',                     // 常见语义类
  'article.video',                   // 文章结构
  '.feed-item',                      // 信息流项
  '.grid-video'                      // 网格布局
];

function findVideoElements() {
  for (const selector of VIDEO_SELECTORS) {
    const elements = document.querySelectorAll(selector);
    if (elements.length > 0) {
      console.log(`[Auto Evolve] 使用选择器: ${selector} (找到 ${elements.length} 个元素)`);
      return elements;
    }
  }
  console.warn('[Auto Evolve] 未找到任何视频项元素，扩展可能无法正常工作。');
  return [];
}

// 替换原有 $('.video-item') 为 findVideoElements()
// 示例：原代码 const items = document.querySelectorAll('.video-item');
// 改为： const items = findVideoElements();
